class Solution:
    def maxDistance(self, position, m: int) -> int:
        position = sorted(position)

        def feasible(d):
            count = 1
            last = position[0]
            for p in position[1:]:
                if p - last >= d:
                    count += 1
                    last = p
            return count >= m

        # A differently-shaped binary search template (searches for the first
        # infeasible d and steps back one) from the main solution's -- an
        # independent check on the boundary arithmetic, still O(n log span) so
        # it stays fast even when the basket span is close to 10^9.
        lo, hi = 1, position[-1] - position[0]
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                lo = mid + 1
            else:
                hi = mid
        return lo - 1 if not feasible(lo) else lo

