var maxDistance = function(position, m) {
    position = position.slice().sort((a, b) => a - b);

    function feasible(d) {
        let count = 1;
        let last = position[0];
        for (let i = 1; i < position.length; i++) {
            if (position[i] - last >= d) {
                count++;
                last = position[i];
            }
        }
        return count >= m;
    }

    let lo = 1, hi = position[position.length - 1] - position[0];
    while (lo < hi) {
        const mid = Math.floor((lo + hi + 1) / 2);
        if (feasible(mid)) {
            lo = mid;
        } else {
            hi = mid - 1;
        }
    }
    return lo;
};
